{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-issue-citation-ordering-warning-artifact-before-snapshot-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的进料流股 feed-16 缺少流量规格的问题，以及受其影响而暂未确认的产物流股 product-16 局部状态，生成最小候选提案。",
      "issues": [
        {
          "title": "进料流股缺少直接求解所需的流量规格",
          "severity": "error",
          "citations": [
            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "title": "出口温度表现受未补全入口条件影响，局部效果暂未确认",
          "severity": "warning",
          "citations": [
            "diag-2",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Cold Feed 添加流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-16"
          },
          "rationale": "诊断直接指出 feed-16 缺少流量规格，且当前求解状态为 invalid_parameters。对该已选中流股补充一个待确认的流量规格占位，是最小且可审查的局部修补建议。",
          "patch": {
            "spec_placeholders": {
              "flow_rate": {
                "required": true,
                "status": "missing",
                "prompt": "请为 Cold Feed 提供流量规格值与单位。"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "将 Heater Outlet 温度标记为待入口条件确认",
          "target": {
            "type": "stream",
            "id": "product-16"
          },
          "rationale": "当前 warning 仅表明 product-16 的温度表现可能仍受缺失入口条件影响，并未提供足够证据去直接修改其数值。故仅建议添加保护性占位，等待上游 feed-16 规格补全后再确认。",
          "patch": {
            "spec_placeholders": {
              "temperature_c": {
                "status": "needs_confirmation",
                "depends_on": [
                  "feed-16.flow_rate"
                ],
                "prompt": "在补全 Cold Feed 流量规格后，复核 Heater Outlet 温度设定/结果是否仍成立。"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        }
      ],
      "confidence": 0.92,
      "citations": [
        "diag-1",
        "diag-2",
        "flowdoc-stream-1",
        "flowdoc-stream-2",
        "snapshot-1"
      ]
    }
